(() => {
    interface Person {
      name: string;
      age: number;
      createdAt: Date;
    }
    return {build: () => createValidate<Partial<Person> & Required<Pick<Person, 'name'>>>(), buildErrors: () => noErrs(createGetValidationErrors<Partial<Person> & Required<Pick<Person, 'name'>>>())};
  })()

{
    build: () => {
      interface Person {
        name: string;
        age: number;
        createdAt: Date;
      }
      const check = typia.createIs<Partial<Person> & Required<Pick<Person, 'name'>>>();
      return (v) => check(v);
    },
    buildErrors: () => {
      interface Person {
        name: string;
        age: number;
        createdAt: Date;
      }
      const val = typia.createValidate<Partial<Person> & Required<Pick<Person, 'name'>>>();
      return (v) => val(v).success;
    },
    samples: {invalid: [{}, {age: 30}, {name: 42}, {name: 'John', age: '30'}, null, undefined]},
  }

c(
    Type.Intersect([
      Type.Partial(Type.Object({name: Type.String(), age: Type.Number(), createdAt: Type.Date()})),
      Type.Required(Type.Pick(Type.Object({name: Type.String(), age: Type.Number(), createdAt: Type.Date()}), ['name'])),
    ])
  )
